// Check whether any social channel (X, Telegram, Discord) is enabled.
// Reads ENABLE_SOCIAL_X, ENABLE_SOCIAL_TELEGRAM, ENABLE_SOCIAL_DISCORD
// from n8n Variables. If all are disabled, skip generation entirely.
const enableX        = ($vars.ENABLE_SOCIAL_X        || '').toLowerCase() === 'true';
const enableTelegram = ($vars.ENABLE_SOCIAL_TELEGRAM  || '').toLowerCase() === 'true';
const enableDiscord  = ($vars.ENABLE_SOCIAL_DISCORD   || '').toLowerCase() === 'true';

if (!enableX && !enableTelegram && !enableDiscord) {
  return [{ json: { _social_skip: true, reason: 'All social channels disabled (X, Telegram, Discord)' } }];
}

const ctx = $input.first().json;

if (!ctx.topic_slug || !ctx.date_key) {
  throw new Error('Missing topic_slug or date_key in input context');
}

if (!ctx.summary) {
  throw new Error(`No summary found in context for ${ctx.topic_slug}/${ctx.date_key}`);
}

return [{
  json: {
    ...ctx,
    _social_enable_x:        enableX,
    _social_enable_telegram: enableTelegram,
    _social_enable_discord:  enableDiscord,
    _social_skip: false
  }
}];

// Reuse the AI output from the Meta social generation step (module 11)
// or from the shared summary context. The AI output format is identical
// — the same post_caption, hashtags, image_prompt, story_caption, cta
// fields feed all platforms. No separate AI call needed.
//
// If ai_output is already available from module 11 (Meta), use it directly.
// Otherwise, build a social content asset from the summary context.
const ctx = $input.first().json;

// Check if we already have AI output from Meta module
const aiOutput = ctx._ai_output || ctx.meta_ai_output || null;

if (aiOutput) {
  // Reuse existing AI output — no additional AI call needed
  return [{ json: { ...ctx, _ai_output: aiOutput } }];
}

// Build a simple social content asset from summary data directly.
// This path is used when Meta social is disabled but X/Telegram/Discord
// are enabled. Uses the summary headline, overview, and key events as caption.
const summary = ctx.summary;

const keyEventsText = (summary.key_events || []).slice(0, 3)
  .map((e, i) => `${i + 1}. ${e.title}: ${e.significance}`)
  .join('\n');

const captionIntro = summary.headline + '. ' + (summary.overview || '').slice(0, 400);
const captionBody = keyEventsText
  ? `${captionIntro}\n\nKey events:\n${keyEventsText}`
  : captionIntro;

const simpleAiOutput = {
  post_caption: captionBody,
  hashtags: [`#${ctx.topic_slug}`, '#news', '#daily'],
  image_prompt: `Daily ${ctx.topic_slug} news summary visual`,
  story_caption: summary.headline ? summary.headline.slice(0, 150) : null,
  story_background_hint: `${ctx.topic_slug} news gradient`,
  cta: `Follow for daily ${ctx.topic_slug} updates.`
};

return [{ json: { ...ctx, _ai_output: simpleAiOutput } }];

// Apply platform-specific formatting to produce the social_content_asset.
// X:        post max 280 chars, hashtags inline, optional thread (gated by ENABLE_SOCIAL_X_THREADS)
// Telegram: HTML-formatted digest, max 4096 chars
// Discord:  embed with title, description, color, fields

const ctx = $input.first().json;
const ai  = ctx._ai_output;

const topicEmoji = {
  crypto: '🪙', finance: '📈', economy: '🏦',
  health: '🏥', ai: '🤖', energy: '⚡', technology: '💻'
};
const discordColor = {
  crypto: 0xF7931A, finance: 0x2ECC71, economy: 0x3498DB,
  health: 0xE74C3C, ai: 0x9B59B6, energy: 0xF1C40F, technology: 0x1ABC9C
};

const topicBaseHashtags = {
  crypto:     ['#crypto', '#blockchain', '#digitalassets', '#web3'],
  finance:    ['#finance', '#investing', '#markets', '#stocks'],
  economy:    ['#economy', '#macroeconomics', '#fed', '#inflation'],
  health:     ['#health', '#wellness', '#medicine', '#healthcare'],
  ai:         ['#AI', '#artificialintelligence', '#machinelearning', '#tech'],
  energy:     ['#energy', '#renewableenergy', '#oilandgas', '#cleanenergy'],
  technology: ['#technology', '#tech', '#innovation', '#software']
};

const baseHashtags = topicBaseHashtags[ctx.topic_slug] || [];
const allHashtags = [...new Set([...(ai.hashtags || []), ...baseHashtags])].slice(0, 30);
const captionBody = (ai.post_caption || '').trim();
const ctaText = ai.cta || `Follow for daily ${ctx.topic_slug} updates.`;
const emoji = topicEmoji[ctx.topic_slug] || '📰';
const topicLabel = ctx.topic_slug.charAt(0).toUpperCase() + ctx.topic_slug.slice(1);
const color = discordColor[ctx.topic_slug] || 0x95A5A6;
const timestamp = new Date().toISOString();

// ── X formatting ──
const xHashtags = allHashtags.slice(0, 5).join(' ');
const xHashBlock = xHashtags ? '\n\n' + xHashtags : '';
const xFull = emoji + ' ' + captionBody + xHashBlock;
const xPostText = xFull.length <= 280
  ? xFull
  : (emoji + ' ' + captionBody).slice(0, 280 - xHashBlock.length - 2) + '…' + xHashBlock;

// X thread — only built when ENABLE_SOCIAL_X_THREADS is explicitly enabled
const threadsEnabled = ($vars.ENABLE_SOCIAL_X_THREADS || '').toLowerCase() === 'true';
let xThread = null;
if (threadsEnabled && captionBody.length > 280) {
  const posts = [];
  let remaining = captionBody;
  while (remaining.length > 0) {
    if (remaining.length <= 280) { posts.push(remaining); break; }
    let splitAt = remaining.lastIndexOf(' ', 276);
    if (splitAt <= 0) splitAt = 276;
    posts.push(remaining.slice(0, splitAt) + ' ...');
    remaining = remaining.slice(splitAt).trim();
  }
  if (posts.length > 1) xThread = posts;
}

// ── Telegram HTML formatting ──
const escHtml = (s) => (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
// Escape hashtags before inserting into HTML to prevent markup injection
const escapedHashtags = allHashtags.map(tag => escHtml(tag));
const telegramText = [
  `${emoji} <b>${topicLabel} Daily Briefing</b> — ${escHtml(ctx.date_key)}`,
  '',
  escHtml(captionBody),
  ctaText ? '\n' + escHtml(ctaText) : '',
  '\n' + escapedHashtags.join(' ')
].filter(Boolean).join('\n');
const telegramMessage = telegramText.length <= 4096
  ? telegramText
  : telegramText.slice(0, 4095) + '…';

// ── Discord embed formatting ──
const discordEmbed = {
  title: (`${emoji} ${topicLabel} Daily Briefing — ${ctx.date_key}`).slice(0, 256),
  description: captionBody.slice(0, 4096),
  color,
  fields: [
    { name: 'Topic', value: topicLabel, inline: true }
  ],
  footer: { text: allHashtags.slice(0, 10).join(' ') },
  timestamp
};
if (ctaText) {
  discordEmbed.fields.push({ name: 'CTA', value: ctaText, inline: false });
}

const enableX        = !!ctx._social_enable_x;
const enableTelegram = !!ctx._social_enable_telegram;
const enableDiscord  = !!ctx._social_enable_discord;

const asset = {
  topic_slug:     ctx.topic_slug,
  date_key:       ctx.date_key,
  asset_type:     'daily_post',
  source_type:    'daily_summary',
  source_id:      null,
  publish_job_id: ctx.publish_job_id || null,
  ai_output: {
    post_caption:          ai.post_caption,
    hashtags:              ai.hashtags,
    image_prompt:          ai.image_prompt,
    story_caption:         ai.story_caption || null,
    story_background_hint: ai.story_background_hint || null,
    cta:                   ai.cta || null
  },
  x: {
    enabled:    enableX,
    post_text:  xPostText,
    thread:     xThread,
    alert_text: null
  },
  telegram: {
    enabled:      enableTelegram,
    message_html: telegramMessage,
    alert_html:   null
  },
  discord: {
    enabled:     enableDiscord,
    embed:       discordEmbed,
    alert_embed: null
  },
  generated_at: timestamp
};

return [{ json: asset }];
